from collections import defaultdict
class Solution:
    def maxTaxiEarnings(self, n, rides):
        by_end = defaultdict(list)
        for s, e, t in rides:
            by_end[e].append((s, t))
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            dp[i] = dp[i - 1]
            for s, t in by_end.get(i, []):
                cand = dp[s] + (i - s + t)
                if cand > dp[i]:
                    dp[i] = cand
        return dp[n]

