var maxTaxiEarnings = function(n, rides) {
    const byEnd = Array.from({length: n + 1}, () => []);
    for (const [s, e, t] of rides) byEnd[e].push([s, t]);
    const dp = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        dp[i] = dp[i - 1];
        for (const [s, t] of byEnd[i]) {
            const cand = dp[s] + (i - s + t);
            if (cand > dp[i]) dp[i] = cand;
        }
    }
    return dp[n];
